import {
  connectTooltip,
  tooltipManager,
  type TooltipPlacement,
  type TooltipConnector,
  type TooltipManager,
} from '@o9ds/core';

export interface O9TooltipOptions {
  /** Text content displayed in the tooltip */
  content: string;
  /** Preferred placement relative to the trigger element */
  placement?: TooltipPlacement;
  /** Keyboard shortcut hint displayed alongside the content */
  shortcut?: string;
}

/**
 * Vanilla JS tooltip component. Attaches tooltip behavior (hover/focus,
 * ARIA, positioning) to any DOM element.
 *
 * ```ts
 * const tip = O9Tooltip.initialize(triggerEl, { content: 'Save' });
 * tip.destroy();
 * ```
 */
export class O9Tooltip {
  private _connector: TooltipConnector;
  private _element: HTMLElement;

  static readonly DEFAULTS: Partial<O9TooltipOptions> = {};

  private constructor(element: HTMLElement, options: O9TooltipOptions, manager: TooltipManager) {
    this._element = element;

    this._connector = connectTooltip(manager, {
      anchor: element,
      content: options.content,
      placement: options.placement,
      shortcut: options.shortcut,
    });
  }

  static initialize(
    element: HTMLElement,
    options: O9TooltipOptions,
    manager?: TooltipManager,
  ): O9Tooltip {
    return new O9Tooltip(element, { ...O9Tooltip.DEFAULTS, ...options }, manager ?? tooltipManager);
  }

  update(options: Partial<O9TooltipOptions>): void {
    this._connector.update({
      content: options.content,
      placement: options.placement,
      shortcut: options.shortcut,
    });
  }

  destroy(): void {
    this._connector.destroy();
  }

  get element(): HTMLElement {
    return this._element;
  }
}
